import{_ as a,o,c as t,an as r}from"./chunks/framework.BftF_wGS.js";const p=JSON.parse('{"title":"Gamma-CDF derivative","description":"","frontmatter":{},"headers":[],"relativePath":"tools/gamma-cdf.md","filePath":"tools/gamma-cdf.md","lastUpdated":null}'),d={name:"tools/gamma-cdf.md"};function i(s,e,c,n,l,m){return o(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="gamma-cdf" tabindex="-1">Gamma-CDF derivative <a class="header-anchor" href="#gamma-cdf" aria-label="Permalink to &quot;Gamma-CDF derivative {#gamma-cdf}&quot;">​</a></h1><h2 id="The-problem" tabindex="-1">The problem <a class="header-anchor" href="#The-problem" aria-label="Permalink to &quot;The problem {#The-problem}&quot;">​</a></h2><p>The regularised lower incomplete gamma <code>P(a, z)</code> is the Gamma CDF, and <code>SpecialFunctions.gamma_inc</code> computes it accurately across every regime. Its <code>ChainRule</code>, though, leaves the partial with respect to the shape parameter <code>a</code> as <code>@not_implemented</code>. A Gamma CDF differentiated in its shape therefore has no derivative on any ChainRules-based backend, and the forward-mode <code>Dual</code> and Enzyme paths hit the same wall.</p><h2 id="The-fix" tabindex="-1">The fix <a class="header-anchor" href="#The-fix" aria-label="Permalink to &quot;The fix {#The-fix}&quot;">​</a></h2><p><code>_gamma_cdf(k, θ, x)</code> evaluates <code>P(k, x/θ)</code> on the primal path through <code>gamma_inc</code>, and the extensions supply the derivative analytically:</p><ul><li><p><code>_grad_p_a_series</code> computes the missing shape partial by term-by-term differentiation of the Tricomi series, following Moore (1982), Algorithm AS 187 — the same construction Stan (<code>grad_reg_inc_gamma</code>) and JAX (<code>igamma_grad_a</code>) use.</p></li><li><p><code>_gamma_cdf_value_and_partials</code> returns the primal and the <code>(dk, dθ, dx)</code> partials from one helper, so the ChainRules rule, the ForwardDiff <code>Dual</code> methods, and the Enzyme rule share the same formulas.</p></li><li><p><code>EpiAwareADToolsChainRulesCoreExt</code> defines the reverse-mode <code>rrule</code> and forward-mode <code>frule</code>; <code>EpiAwareADToolsReverseDiffExt</code> and <code>EpiAwareADToolsMooncakeExt</code> lift these into their backends; <code>EpiAwareADToolsForwardDiffExt</code> adds <code>Dual</code> methods directly; and <code>EpiAwareADToolsEnzymeExt</code> adds a direct Enzyme rule.</p></li></ul><p>The Enzyme extension also carries a rule for <code>SpecialFunctions.gamma</code>, whose own Enzyme lowering is wrong by a factor of <code>Γ(x)</code> (an upstream Enzyme bug); the gamma density in <code>_gamma_cdf_value_and_partials</code> needs it.</p><p>This machinery is internal. Consumers reach it through the <a href="/EpiAwareADTools.jl/previews/PR6/tools/ad-safe-hooks#ad-safe-hooks">AD-safe hooks</a>; the <a href="/EpiAwareADTools.jl/previews/PR6/lib/internals#Internal-Documentation">Internal API</a> page carries the full docstrings.</p><h2 id="Upstream-target" tabindex="-1">Upstream target <a class="header-anchor" href="#Upstream-target" aria-label="Permalink to &quot;Upstream target {#Upstream-target}&quot;">​</a></h2><p>The whole family stands in for a differentiable <code>gamma_inc</code>. <a href="https://github.com/JuliaMath/SpecialFunctions.jl/issues/531" target="_blank" rel="noreferrer">SpecialFunctions.jl issue #531</a> tracks the missing shape derivative. Once <code>gamma_inc</code> carries a complete <code>ChainRule</code>, <code>_gamma_cdf</code> and its rules are deleted and the hooks route through the stock CDF.</p>',10)])])}const f=a(d,[["render",i]]);export{p as __pageData,f as default};
